    // map() throws IllegalArgumentException
    final char mappedChar = this.map(str.charAt(index));
    // HW rule check
    if (index > 1 && mappedChar != '0') {
        final char hwChar = str.charAt(index - 1); /* bug is here */
        if ('H' == hwChar || 'W' == hwChar) { /* bug is here */
            final char preHWChar = str.charAt(index - 2); /* bug is here */
            final char firstCode = this.map(preHWChar); /* bug is here */
            if (firstCode == mappedChar || 'H' == preHWChar || 'W' == preHWChar) { /* bug is here */
                return 0;
            } /* bug is here */
        }
    }
    return mappedChar;
}
[Buggy Code's Comments]: /**
* Used internally by the Soundex algorithm.
*
* Consonants from the same code group separated by W or H are treated as one.
*
* @param str
*                  the cleaned working string to encode (in upper case).
* @param index
*                  the character position to encode
* @return Mapping code for a particular character
* @throws IllegalArgumentException
*                  if the character is not mapped
*/
[Issue Title]: Bug in HW rule in Soundex
[Issue Description]: The Soundex algorithm says that if two characters that map to the same code are separated by H or W, the second one is not encoded.
However, in the implementation (in Soundex.getMappingCode() line 191), a character that is preceded by two characters that are either H or W, is not encoded, regardless of what the last consonant was.
Source: http://en.wikipedia.org/wiki/Soundex#American_Soundex

[Trigger Test 1]
Test Name: testHWRuleEx1
Test Source:     public void testHWRuleEx1() {

        // From

        // http://www.archives.gov/research_room/genealogy/census/soundex.html:

        // Ashcraft is coded A-261 (A, 2 for the S, C ignored, 6 for the R, 1

        // for the F). It is not coded A-226.

        Assert.assertEquals("A261", this.getStringEncoder().encode("Ashcraft"));

        Assert.assertEquals("A261", this.getStringEncoder().encode("Ashcroft"));

        Assert.assertEquals("Y330", this.getStringEncoder().encode("yehudit"));

        Assert.assertEquals("Y330", this.getStringEncoder().encode("yhwdyt"));

    }

Error Message: junit.framework.AssertionFailedError: expected:<Y3[3]0> but was:<Y3[0]0>
	at org.apache.commons.codec.language.SoundexTest.testHWRuleEx1(SoundexTest.java:232)  Assert.assertEquals("Y330", this.getStringEncoder().encode("yhwdyt"));

[Ground Truth Patch]: private char getMappingCode(final String str, final int index) {
    // map() throws IllegalArgumentException
    final char mappedChar = this.map(str.charAt(index));
    // HW rule check
    if (index > 1 && mappedChar != '0') {
        for (int i=index-1 ; i>=0 ; i--) {
            final char prevChar = str.charAt(i);
            if (this.map(prevChar)==mappedChar) {
                return 0;
            }
            if ('H'!=prevChar && 'W'!=prevChar) {
                break;
            }
        }
    }
    return mappedChar;
}
